// screenfull stub
var screenfull = {
  enabled: !!(document.fullscreenEnabled || document.webkitFullscreenEnabled),
  isFullscreen: false,
  request: function(el) { (el||document.documentElement).requestFullscreen && (el||document.documentElement).requestFullscreen(); },
  exit: function() { document.exitFullscreen && document.exitFullscreen(); },
  toggle: function(el) { this.isFullscreen ? this.exit() : this.request(el); },
  on: function(){}, off: function(){}
};
